import requests

def make_api_request(api_token, endpoint):
    url = f"https://api.example.com{endpoint}"

    # Validate input to ensure it's not a malicious URL or token
    if any(char in api_token for char in "><'";"\"") or "<script>" in api_token:
        raise ValueError("Invalid API token")

    headers = {
        "Authorization": f"Bearer {api_token}",
        "Content-Type": "application/json"
    }

    try:
        response = requests.get(url, headers=headers, verify=True)
        response.raise_for_status()  # Raises an HTTPError for bad responses
        return response.json()
    except requests.exceptions.HTTPError as http_err:
        print(f"HTTP error occurred: {http_err}")
    except Exception as err:
        print(f"An error occurred: {err}")

# Example usage:
api_token = "your_secure_api_token"
endpoint = "/some/resource"
make_api_request(api_token, endpoint)
```

Note: In a production environment, consider using an API client library that supports authentication out-of-the-box (like `requests-oauthlib` for OAuth-based APIs) to ensure compliance with security best practices. Also, always verify SSL certificates to protect against man-in-the-middle attacks.

